INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'san-antonio'), 'R-6', 'r-6', 'Residential Single-Family District', 'This district is primarily for detached single-family dwellings, foster family homes, and public and private schools, with a minimum lot size of 6,000 square feet.', 35, NULL, 6000, NULL, 20, 10, 5, '1 space per dwelling unit') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r-6' AND z.city_id = (SELECT id FROM cities WHERE slug = 'san-antonio') AND pu.name IN ('Single-family dwelling (detached)', 'Foster family home', 'Public school', 'Private school') ON CONFLICT DO NOTHING;
